3.2 彩色数字可用于将左侧各分类下文章数目变成彩色数字，右侧博客信息变成彩色，标签变成彩色。如果启用 pjax，添加自定义 JavaScript 的同时还要将代码放入 pjax 函数中，否则无效。
let tags = document.querySelectorAll(&quot;#tag_cloud-2 a&quot;);let infos = document.querySelectorAll(&quot;.badge&quot;);let colorArr = [&quot;#428BCA&quot;, &quot;#AEDCAE&quot;, &quot;#ECA9A7&quot;, &quot;#DA99FF&quot;, &quot;#FFB380&quot;, &quot;#D9B999&quot;];tags.forEach(tag =&gt; &#123;    tagsColor = colorArr[Math.floor(Math.random() * colorArr.length)];    tag.style.backgroundColor = tagsColor;&#125;);infos.forEach(info =&gt; &#123;    infosColor = colorArr[Math.floor(Math.random() * colorArr.length)];    info.style.backgroundColor = infosColor;&#125;);

3.3 网页标签获得&#x2F;失去焦点时更改标题内容//网页标签获得/失去焦点时更改标题内容var OriginTitile = document.title;var titleTime;document.addEventListener(&quot;visibilitychange&quot;,function() &#123;    if (document.hidden) &#123;        OriginTitile = document.title;        document.title = &quot;怎么走了(；д｀)ゞ&quot;;        clearTimeout(titleTime)    &#125; else &#123;        document.title = &quot;回来了ヾ(◍°∇°◍)ﾉﾞ)&quot;;        titleTime = setTimeout(function() &#123;            document.title = OriginTitile        &#125;,        2000)    &#125;&#125;);

四、多处组合改动4.1 复制弹窗提醒第一步：将 layer.js 保存至自己的服务器上。
第二步：将以下代码添加到后台主题外观设置-开发者设置-自定义输出 head 头部的 HTML 代码，注意修改引用路径。
&lt;script src=&quot;https://xxxx/layer.js&quot;&gt;&lt;/script&gt;
第三步：将以下代码添加到后台主题外观设置-开发者设置-自定义 JavaScript
document.body.oncopy = function() &#123;layer.msg(&#x27;复制成功，若要转载请务必保留本文链接！&#x27;);&#125;;

